sql:
SELECT program_id, program_name
FROM football_programs
WHERE conference LIKE 'B%';

SELECT program_name, player_count
FROM football_programs
ORDER BY player_count DESC;

SELECT program_name, founded_year
FROM football_programs
WHERE founded_year > 1900 AND enrollment > 50000;

SELECT f.fan_name
FROM fans f
JOIN enrollment_history eh ON f.program_id = eh.program_id
WHERE eh.enrollment = (
    SELECT MAX(enrollment) FROM enrollment_history
);

SELECT scholarships.type, events.event_name, events.event_date
FROM scholarships
JOIN events ON scholarships.program_id = events.program_id;

SELECT DISTINCT coaches.coach_name
FROM coaches
JOIN football_programs ON coaches.coach_id = football_programs.head_coach_id;

SELECT player_name 
FROM players 
WHERE program_id IN (SELECT program_id FROM scholarships);

SELECT program_name
FROM football_programs
WHERE enrollment > (SELECT AVG(enrollment) FROM football_programs);

SELECT program_name, SUM(enrollment) AS total_enrollment
FROM football_programs
GROUP BY program_name;

SELECT fp.program_name, fp.enrollment_ratio
FROM football_programs fp
WHERE fp.enrollment_ratio > (SELECT AVG(fp1.enrollment_ratio) FROM football_programs fp1);

SELECT *
FROM football_programs
WHERE program_id = (SELECT program_id FROM players WHERE player_name = 'John Doe');

external_knowledge:
- "setting their sails the furthest into the horizon" refers to having the highest year of eligibility;
- "football program’s flag" metaphorically represents the football program they belong to;
- "captains and their ships" metaphorically represents the player names and the football programs, respectively;
- "last charted new territories" is a metaphor for the most recent year of eligibility.

sql:
SELECT players.player_name, football_programs.program_name 
FROM players
INNER JOIN football_programs ON players.program_id = football_programs.program_id;

SELECT program_name, conference, enrollment, player_count, enrollment_ratio
FROM football_programs
ORDER BY enrollment_ratio DESC;

SELECT type
FROM scholarships
WHERE amount > 10000.0;

SELECT program_id, program_name, player_count
FROM football_programs
WHERE player_count > (SELECT AVG(player_count) FROM football_programs);

SELECT program_id, SUM(amount) AS Total_Sponsorship_Amount
FROM sponsorships
GROUP BY program_id;

SELECT program_id, enrollment 
FROM football_programs 
WHERE enrollment > 40000;

SELECT fp.*, c.* 
FROM football_programs fp 
JOIN conferences c ON fp.conference = c.conference_name;
